import React, { useState, useEffect } from 'react';
import Box from '@mui/material/Box';
import Container from '@mui/material/Container';
import Typography from '@mui/material/Typography';
import Breadcrumbs from '@mui/material/Breadcrumbs';
import Link from '@mui/material/Link';
import List from '@mui/material/List';
import ListItem from '@mui/material/ListItem';
import ImageListItem from '@mui/material/ImageListItem';
import ListItemText from '@mui/material/ListItemText';
import Divider from '@mui/material/Divider';
import Skeleton from '@mui/material/Skeleton';
import { API } from '../../tools/API';

export default function Portfolio() {
  const [myportfolio, setMyPortfolio] = useState([]);

  useEffect(() => {
    const fetchData = async () => {
      await fetch(`https://sheets.googleapis.com/v4/spreadsheets/${API.SPREADSHEET}/values/${API.SPREADSHEET_PORTFOLIO}?key=${API.KEY}`)
      .then(res => res.json())
      .then(data => {
        setMyPortfolio(data.values.slice(1).reverse());
      });
    };

    fetchData();

  }, []);

  return(
    <>
    <Box
      sx={{
        flexGrow: 1,
        backgroundColor: '#f5f5f5',
        pt: 13,
        pb: 5,
      }}
    >
      <Container>
        <Breadcrumbs aria-label="breadcrumb">
          <Link underline="hover" color="inherit" href="/">
            Home
          </Link>
          <Typography color="text.primary">Portfolio</Typography>
        </Breadcrumbs>
      </Container>
    </Box>
    <Box
      sx={{
        flexGrow: 1,
        pb: 5,
      }}
    >
      <Container>
        <List sx={{ width: '100%', bgcolor: 'background.paper', p: 0 }}>
          {myportfolio.length > 0 ? 
            myportfolio.map((portfolio,i) => (
              <>
              <ListItem alignItems="flex-start">
                <ImageListItem key={i} sx={{ width: { xs: 75, md: 150 }, px: 1, m: 'auto' }}>
                  <img
                    alt="logo"
                    src={portfolio[5]}
                  />
                </ImageListItem>
                <ListItemText
                  primary={portfolio[2].length > 0 ? <Typography variant="h6" component="div"><Link href={portfolio[2]} sx={{ color: 'rgba(0, 0, 0, 0.87)', textDecoration: 'none', '&:hover': { color: 'rgba(64, 64, 64, 0.87)' } }} target="_blank">{portfolio[3]}</Link></Typography> : <Typography variant="h6" component="div">{portfolio[3]}</Typography>}
                  secondary={
                    <>
                    <div style={{ width: '100%' }}>
                      <Typography variant="body1" component="div" sx={{ fontSize: 17, fontWeight: 500 }}>{portfolio[1]}</Typography>
                      <Typography variant="body1" component="div" sx={{ WebkitLineClamp: 3, display: '-webkit-box', WebkitBoxOrient: 'vertical', overflow: 'hidden' }}>{portfolio[4]}</Typography>
                    </div>
                    </>
                  }
                  sx={{ width: '90%', px: 1 }}
                />
              </ListItem>
              {i < (myportfolio.length - 1) ? <Divider /> : null}
              </>
            ))
          :
            [1,2,3,4].map((_,i) => (
              <Skeleton key={i} animation="wave" width="100%" height={200} />
            ))
          }
        </List>
      </Container>
    </Box>
    </>
  )
}