import React, { useState, useEffect } from 'react';
import Box from '@mui/material/Box';
import Grid from '@mui/material/Grid';
import Container from '@mui/material/Container';
import Avatar from '@mui/material/Avatar';
import Typography from '@mui/material/Typography';
import Skeleton from '@mui/material/Skeleton';
import Link from '@mui/material/Link';
import Stack from '@mui/material/Stack';
import Button from '@mui/material/Button';
import Paper from '@mui/material/Paper';
import List from '@mui/material/List';
import ListItemButton from '@mui/material/ListItemButton';
import ListItemText from '@mui/material/ListItemText';
import Divider from '@mui/material/Divider';
import TwitterIcon from '@mui/icons-material/Twitter';
import LinkedInIcon from '@mui/icons-material/LinkedIn';
import GitHubIcon from '@mui/icons-material/GitHub';
import EmailIcon from '@mui/icons-material/Email';
import { getPages } from '../../tools/Connector';
import { API } from '../../tools/API';

export default function Home() {
  const [mydata, setMyData] = useState([]);
  const [skills, setSkills] = useState([]);
  const [myportfolio, setMyPortfolio] = useState([]);
  const sosmedIcon = [<TwitterIcon fontSize="large" />, <LinkedInIcon fontSize="large" />, <GitHubIcon fontSize="large" />, <EmailIcon fontSize="large" />]

  useEffect(() => {
    const fetchData = async () => {
      await Promise.all([
        fetch(`https://sheets.googleapis.com/v4/spreadsheets/${API.SPREADSHEET}/values/${API.SPREADSHEET_DATA}?key=${API.KEY}`).then(res1 => res1.json()),
        fetch(`https://sheets.googleapis.com/v4/spreadsheets/${API.SPREADSHEET}/values/${API.SPREADSHEET_SKILLS}?key=${API.KEY}`).then(res2 => res2.json()),
        fetch(`https://sheets.googleapis.com/v4/spreadsheets/${API.SPREADSHEET}/values/${API.SPREADSHEET_PORTFOLIO}?key=${API.KEY}`).then(res3 => res3.json())
      ]).then(([data1,data2,data3]) => {
        setMyData(data1.values.slice(1));
        setSkills(data2.values.slice(1));
        setMyPortfolio(data3.values.slice(1).reverse());
      });
    };

    fetchData();
  }, [])

  return(
    <>
    <Box
      sx={{
        flexGrow: 1,
        minHeight: 600,
        backgroundColor: '#f5f5f5',
        pt: 22,
        pb: 22,
      }}
    >
      <Container>
        <Grid container sx={{ mb: 2 }}>
          <Grid item xs md>
          </Grid>
          <Grid item xs={12} md={6}>
            {mydata.length > 0 ?  
              <Avatar
                alt={mydata[0][1]}
                src={mydata[0][0]}
                sx={{ m: 'auto', width: 150, height: 150 }}
              />
            :
              <Skeleton variant="circular" animation="wave" width={150} height={150} sx={{ m: 'auto' }} />
            }
          </Grid>
          <Grid item xs md>
          </Grid>
        </Grid>
        <Grid container>
          <Grid item xs md>
          </Grid>
          <Grid item xs={12} md={6}>
            {mydata.length > 0 ?  
              <Typography variant="h4" gutterBottom={false} component="div" align="center" sx={{ fontWeight: 500 }}>
                {mydata[0][1]}
              </Typography>
            :
              <Skeleton height={42} animation="wave" sx={{ width: '50%', m: 'auto' }} />
            }
          </Grid>
          <Grid item xs md>
          </Grid>
        </Grid>
        <Grid container sx={{ mb: 2 }}>
          <Grid item xs md>
          </Grid>
          <Grid item xs={12} md={6}>
            {mydata.length > 0 ?  
              <Typography variant="h6" gutterBottom={false} component="div" align="center" sx={{ fontWeight: 400 }}>
                {mydata[0][2]}
              </Typography>
            :
              <Skeleton height={32} animation="wave" sx={{ width: '50%', m: 'auto' }} />
            }
          </Grid>
          <Grid item xs md>
          </Grid>
        </Grid>
        <Grid container sx={{ mb: 2 }}>
          <Grid item xs md>
          </Grid>
          <Grid item xs={12} md={6} sx={{ display: 'flex' }}>
            {mydata.length > 0 ?  
              <Stack direction="row" spacing={2} sx={{ m: 'auto' }}>
                {mydata[0].slice(5).map((sosmed, i) => (
                  <Link key={i} className="social" href={sosmed} target="_blank" sx={{ color: 'rgba(0, 0, 0, 0.87)' }}>
                    {sosmedIcon[i]}
                  </Link>
                ))}
              </Stack>
            :
              <Stack direction="row" spacing={2} sx={{ m: 'auto' }}>
                {sosmedIcon.map((_, i) => (
                  <Skeleton key={i} variant="circular" animation="wave" width={35} height={35} />
                ))}
              </Stack>
            }
          </Grid>
          <Grid item xs md>
          </Grid>
        </Grid>
        <Grid container>
          <Grid item xs md>
          </Grid>
          <Grid item xs={12} md={6} sx={{ display: 'flex' }}>
            {mydata.length > 0 ?  
              <Button variant="outlined" size="large" color="inherit" onClick={() => getPages('/portfolio',1)} sx={{ m: 'auto', boxShadow: '4px 4px 0 0 #464646', '&:hover': { boxShadow: 'none' } }}>My Project</Button>
            :
              <Skeleton animation="wave" width={140} height={70} sx={{ m: 'auto' }} />
            }
          </Grid>
          <Grid item xs md>
          </Grid>
        </Grid>
      </Container>
    </Box>

    <Box
      sx={{
        flexGrow: 1,
        pt: 10,
        pb: 10,
      }}
    >
      <Container>
      {mydata.length > 0 ? 
        <>
        <Typography variant="h4" component="div" sx={{ fontWeight: 500, mb: 1 }}>
          Personal Details
        </Typography>
        <Typography variant="body1" component="p" align="justify" sx={{ fontSize: 20, mb: 2, borderLeft: { xs: 'none', md: '3px solid rgba(0,0,0,.85)' }, paddingLeft: { xs: 0, md: 2 } }}>
          {mydata[0][3]}
        </Typography>
        <Button variant="outlined" size="large" color="inherit" onClick={() => getPages('/about',1)} sx={{ m: 'auto', boxShadow: '4px 4px 0 0 #464646', '&:hover': { boxShadow: 'none' } }}>More About Me</Button>
        </>
      :
        <>
        <Skeleton width={250} height={42} animation="wave" />
        <Skeleton animation="wave" height={100} sx={{ width: '100%' }} />
        <Skeleton animation="wave" width={150} height={70} />
        </>
      }
      </Container>
    </Box>
    
    <Box
      sx={{
        flexGrow: 1,
        backgroundColor: '#f5f5f5',
        pt: 15,
        pb: 15,
      }}
    >
      <Container>
        <Typography variant="h4" component="div" align="center" sx={{ fontWeight: 500, mb: 5 }}>
          Skills
        </Typography>
        <Box sx={{ flexGrow: 1 }}>
          <Grid container spacing={{ xs: 2, md: 3 }} columns={{ xs: 4, sm: 8, md: 12 }}>
            {skills.length > 0 ? 
              skills.map((skill,i) => (
                <Grid item xs={4} sm={4} md={4} key={i}>
                  <Paper elevation={0} sx={{ pl: 3, pr: 3, pt: 2, pb: 2, boxShadow: '4px 4px 0 0 #464646', height: 205, mb: { xs: 2 } }}>
                    <Typography variant="h6" component="div" sx={{ mb: 1 }}>{skill[1]}</Typography>
                    <Typography variant="body1" component="div" align="justify">{skill[2]}</Typography>
                  </Paper>
                </Grid>
              ))
            :
              [1,2,3,4,5,6].map((_,i) => (
                <Grid item xs={4} sm={4} md={4} key={i}>
                  <Skeleton key={i} animation="wave" width="100%" height={125} />
                </Grid>
              ))
            }
          </Grid>
        </Box>
      </Container>
    </Box>
    
    <Box
      sx={{
        flexGrow: 1,
        pt: 10,
        pb: 10,
      }}
    >
      <Container>
        <Typography variant="h4" component="div" sx={{ fontWeight: 500, mb: 1 }}>
          Latest Activities
        </Typography>
        <List sx={{ width: '100%', bgcolor: 'background.paper' }}>
          {myportfolio.length > 0 ? 
            myportfolio.slice(0,5).map((portfolio,i) => (
              <>
              <ListItemButton 
                disableGutters
                onClick={(e) => portfolio[2].length > 0 ? window.open(portfolio[2],"_blank") : e.preventDefault()}
              >
                <ListItemText
                  primary={<Typography variant="h6" component="div">{portfolio[3]} ─ {portfolio[1].substring(2)}</Typography>}
                  secondary={portfolio[4]}
                  sx={{ m: 0 }}
                />
              </ListItemButton>
              {i < (myportfolio.slice(0,5).length - 1) ? <Divider /> : null}
              </>
            ))
          :
            [1,2,3,4,5].map((_,i) => (
              <Skeleton key={i} animation="wave" width="100%" height={125} />
            ))
          }
        </List>
      </Container>
    </Box>
    </>
  )
}