import React, { useState, useEffect } from 'react';
import PropTypes from 'prop-types';
import Box from '@mui/material/Box';
import Grid from '@mui/material/Grid';
import Container from '@mui/material/Container';
import Typography from '@mui/material/Typography';
import Breadcrumbs from '@mui/material/Breadcrumbs';
import Avatar from '@mui/material/Avatar';
import Skeleton from '@mui/material/Skeleton';
import Stack from '@mui/material/Stack';
import Link from '@mui/material/Link';
import Tabs from '@mui/material/Tabs';
import Tab from '@mui/material/Tab';
import Divider from '@mui/material/Divider';
import TwitterIcon from '@mui/icons-material/Twitter';
import LinkedInIcon from '@mui/icons-material/LinkedIn';
import GitHubIcon from '@mui/icons-material/GitHub';
import EmailIcon from '@mui/icons-material/Email';
import { API } from '../../tools/API';

function TabPanel(props) {
  const { children, value, index, ...other } = props;

  return (
    <div
      role="tabpanel"
      hidden={value !== index}
      id={`simple-tabpanel-${index}`}
      aria-labelledby={`simple-tab-${index}`}
      {...other}
    >
      {value === index && (
        <Box sx={{ p: 3 }}>
          <Typography>{children}</Typography>
        </Box>
      )}
    </div>
  );
}

TabPanel.propTypes = {
  children: PropTypes.node,
  index: PropTypes.number.isRequired,
  value: PropTypes.number.isRequired,
};

function a11yProps(index) {
  return {
    id: `simple-tab-${index}`,
    'aria-controls': `simple-tabpanel-${index}`,
  };
}

export default function About() {
  const [mydata, setMyData] = useState([]);
  const [experiences, setExperiences] = useState([]);
  const [valTab, setValTab] = React.useState(0);
  const sosmedIcon = [<TwitterIcon fontSize="large" />, <LinkedInIcon fontSize="large" />, <GitHubIcon fontSize="large" />, <EmailIcon fontSize="large" />]

  useEffect(() => {
    const fetchData = async () => {
      await Promise.all([
        fetch(`https://sheets.googleapis.com/v4/spreadsheets/${API.SPREADSHEET}/values/${API.SPREADSHEET_DATA}?key=${API.KEY}`).then(res1 => res1.json()),
        fetch(`https://sheets.googleapis.com/v4/spreadsheets/${API.SPREADSHEET}/values/${API.SPREADSHEET_EXPERIENCE}?key=${API.KEY}`).then(res2 => res2.json())
      ]).then(([data1,data2]) => {
        setMyData(data1.values.slice(1));
        setExperiences(data2.values.slice(1).reverse());
      });
    };

    fetchData();
  }, [])

  const handleChangeTab = (event, newValue) => {
    setValTab(newValue);
  };

  return(
    <>
    <Box
      sx={{
        flexGrow: 1,
        backgroundColor: '#f5f5f5',
        pt: 13,
        pb: 13,
      }}
    >
      <Container>
        <Breadcrumbs aria-label="breadcrumb">
          <Link underline="hover" color="inherit" href="/">
            Home
          </Link>
          <Typography color="text.primary">About Me</Typography>
        </Breadcrumbs>
      </Container>
    </Box>
    <Box
      sx={{
        flexGrow: 1,
        backgroundColor: '#f5f5f5',
        pb: 13,
      }}
    >
      <Container>
        <Grid container sx={{ mb: 2 }}>
          <Grid item xs md>
          </Grid>
          <Grid item xs={12} md={6}>
            {mydata.length > 0 ?  
              <Avatar
                alt={mydata[0][1]}
                src={mydata[0][0]}
                sx={{ m: 'auto', width: 150, height: 150 }}
              />
            :
              <Skeleton variant="circular" animation="wave" width={150} height={150} sx={{ m: 'auto' }} />
            }
          </Grid>
          <Grid item xs md>
          </Grid>
        </Grid>
        <Grid container>
          <Grid item xs md>
          </Grid>
          <Grid item xs={12} md={6}>
            {mydata.length > 0 ?  
              <Typography variant="h4" gutterBottom={false} component="div" align="center" sx={{ fontWeight: 500 }}>
                {mydata[0][1]}
              </Typography>
            :
              <Skeleton height={42} animation="wave" sx={{ width: '50%', m: 'auto' }} />
            }
          </Grid>
          <Grid item xs md>
          </Grid>
        </Grid>
        <Grid container sx={{ mb: 2 }}>
          <Grid item xs md>
          </Grid>
          <Grid item xs={12} md={6}>
            {mydata.length > 0 ?  
              <Typography variant="h6" gutterBottom={false} component="div" align="center" sx={{ fontWeight: 400 }}>
                {mydata[0][2]}
              </Typography>
            :
              <Skeleton height={32} animation="wave" sx={{ width: '50%', m: 'auto' }} />
            }
          </Grid>
          <Grid item xs md>
          </Grid>
        </Grid>
        <Grid container sx={{ mb: 2 }}>
          <Grid item xs md>
          </Grid>
          <Grid item xs={12} md={6} sx={{ display: 'flex' }}>
            {mydata.length > 0 ?  
              <Stack direction="row" spacing={2} sx={{ m: 'auto' }}>
                {mydata[0].slice(5).map((sosmed, i) => (
                  <Link key={i} className="social" href={sosmed} target="_blank" sx={{ color: 'rgba(0, 0, 0, 0.87)' }}>
                    {sosmedIcon[i]}
                  </Link>
                ))}
              </Stack>
            :
              <Stack direction="row" spacing={2} sx={{ m: 'auto' }}>
                {sosmedIcon.map((_, i) => (
                  <Skeleton key={i} variant="circular" animation="wave" width={35} height={35} />
                ))}
              </Stack>
            }
          </Grid>
          <Grid item xs md>
          </Grid>
        </Grid>
      </Container>
    </Box>
    <Box
      sx={{
        flexGrow: 1,
        pt: 5,
        pb: 5,
      }}
    >
      <Container>
        <Box sx={{ width: '100%' }}>
          {mydata.length > 0 ?  
            <Box sx={{ borderBottom: 1, borderColor: 'divider' }}>
              <Tabs value={valTab} onChange={handleChangeTab} aria-label="about me">
                <Tab sx={{ fontSize: 20 }} label="About Me" {...a11yProps(0)} />
                <Tab sx={{ fontSize: 20 }} label="My Experiences" {...a11yProps(1)} />
              </Tabs>
            </Box>
          :
            <Skeleton animation="wave" width="100%" height={75} />
          }
          <TabPanel value={valTab} index={0}>
            {mydata.length > 0 ?  
              mydata[0][4].split(';').map((item,i) => (
              <Typography key={i} variant="body1" component="div" align="justify" sx={{ fontSize: 20, mb: i < (mydata[0][4].split(';').length-1) ? 2 : 0 }}>
                {item}
              </Typography>
              ))
            :
              <Skeleton animation="wave" width="100%" height={250} />
            }
          </TabPanel>
          <TabPanel value={valTab} index={1}>
            {experiences.length > 0 ?  
              experiences.map((experience,i) => (
                <>
                  <Box sx={{ py: 2 }}>
                    <Typography variant="h5" component="div">{experience[1]}</Typography>
                    <Typography variant="h6" component="div">{experience[2]}</Typography>
                    {experience[3].length > 0 ? <Typography variant="body1" component="div">{experience[3]}</Typography> : null}
                    <Typography variant="body1" component="div">{experience[4]}</Typography>
                  </Box>
                  {i < (experiences.length - 1) ? <Divider /> : null}
                </>
              ))
            :
              [1,2,3,4,5].map((_,i) => (
                <Skeleton key={i} animation="wave" width="100%" height={250} />
              ))
            }
          </TabPanel>
        </Box>
      </Container>
    </Box>
    </>
  )
}