import React, { useEffect, useState } from 'react';
import PropTypes from 'prop-types';
import AppBar from '@mui/material/AppBar';
import Box from '@mui/material/Box';
import Toolbar from '@mui/material/Toolbar';
import Typography from '@mui/material/Typography';
import Container from '@mui/material/Container';
import Button from '@mui/material/Button';
import CssBaseline from '@mui/material/CssBaseline';
import useScrollTrigger from '@mui/material/useScrollTrigger';
import Link from '@mui/material/Link';
import Skeleton from '@mui/material/Skeleton';
import Drawer from '@mui/material/Drawer';
import List from '@mui/material/List';
import Divider from '@mui/material/Divider';
import ListItem from '@mui/material/ListItem';
import ListItemText from '@mui/material/ListItemText';
import MenuIcon from '@mui/icons-material/Menu';
import { API } from '../tools/API';
import { ThemeProvider, createTheme } from '@mui/material/styles';

function ElevationScroll(props) {
  const { children, window } = props;
  // Note that you normally won't need to set the window ref as useScrollTrigger
  // will default to window.
  // This is only being set here because the demo is in an iframe.
  const trigger = useScrollTrigger({
    disableHysteresis: true,
    threshold: 0,
    target: window ? window() : undefined,
  });

  return React.cloneElement(children, {
    elevation: trigger ? 2 : 0,
    style: {
      backgroundColor: trigger ? '#ffffff' : 'transparent',
    }
  });
}

ElevationScroll.propTypes = {
  children: PropTypes.element.isRequired,
  window: PropTypes.func,
};


const primaryTheme = createTheme({
  palette: {
    mode: 'light',
    primary: {
      main: '#ffffff',
    },
  },
});

export default function Headers(props) {
  const [anchorDrawer, setAnchorDrawer] = useState(false);
  const [pages, setPages] = useState([]);
  
  useEffect(() => {
    const fetchData = async () => {
      await fetch(
        `https://sheets.googleapis.com/v4/spreadsheets/${API.SPREADSHEET}/values/${API.SPREADSHEET_PAGES}?key=${API.KEY}`
      ).then(res => res.json())
      .then((data) => {
        setPages(data.values.slice(1));
      });
    };

    fetchData();
  }, [])

  const toggleDrawer = (open) => {
    setAnchorDrawer(open);
  };

  return(
    <ThemeProvider theme={primaryTheme}>
      <CssBaseline />
      <ElevationScroll {...props}>
        <AppBar>
          <Container maxWidth="xl">
            <Toolbar>
              <Typography
                variant="h6"
                noWrap
                component="div"
                sx={{ flexGrow: 1, display: { xs: 'none', md: 'flex' } }}
              >
                <Link href="/" sx={{ color: 'rgba(0, 0, 0, 0.87)', fontSize: 24, textDecoration: 'none' }}>
                  Aditya Adam F.
                </Link>
              </Typography>
              <Typography
                variant="h6"
                noWrap
                component="div"
                sx={{ flexGrow: 1, display: { xs: 'flex', md: 'none' } }}
              >
                <Link href="/" sx={{ color: 'rgba(0, 0, 0, 0.87)', textDecoration: 'none' }}>
                  Aditya Adam F.
                </Link>
              </Typography>

              <Box sx={{ flexGrow: 0, display: { xs: 'flex', md: 'none' } }}>
                {pages.length > 0 ? 
                  <>
                  <Button onClick={() => toggleDrawer(true)}>
                    <MenuIcon sx={{ color: 'rgba(0, 0, 0, 0.87)' }} />
                  </Button>
                  <Drawer
                    anchor="top"
                    open={anchorDrawer}
                    onClose={() => toggleDrawer(false)}
                  >
                    <Box
                      sx={{ width: 'auto' }}
                      role="presentation"
                      onClick={() => toggleDrawer(false)}
                      onKeyDown={() => toggleDrawer(false)}
                    >
                      <List>
                        {pages.map((page,i) => (
                          <>
                          <Link href={page[1] === 'home' ? '/' : '/'+page[1]} sx={{ color: 'rgba(0, 0, 0, 0.87)', textDecoration: 'none' }}>
                            <ListItem button key={i}>
                              <ListItemText primary={page[1]} sx={{ textTransform: "uppercase" }} />
                            </ListItem>
                          </Link>
                          {i < (pages.length - 1) ? <Divider /> : null}
                          </>
                        ))}
                      </List>
                    </Box>
                  </Drawer>
                  </>
                :
                  <Skeleton animation="wave" width={50} height={25} />
                }
              </Box>
              <Box sx={{ flexGrow: 0, display: { xs: 'none', md: 'flex' } }}>
                {pages.length > 0 ? 
                  pages.map((page,i) => (
                    <>
                    <Button
                      key={i}
                      href={page[1] === 'home' ? '/' : '/'+page[1]}
                      sx={{ 
                        mr: 2,
                        my: 2, 
                        color: 'rgba(0, 0, 0, 0.87)', 
                        fontSize: 18, 
                        display: 'block', 
                        '&:last-child': {
                          mr: 0
                        }
                      }}
                    >
                      {page[1]}
                    </Button>
                    </>
                  ))
                :
                  pages.map((_,i) => (
                    <Skeleton key={i} animation="wave" width={100} height={25} sx={{ mr: 2, my: 2, '&:last-child': { mr: 0 } }} />
                  ))
                }
              </Box>
            </Toolbar>
          </Container>
        </AppBar>
      </ElevationScroll>
    </ThemeProvider>
  )
}