import React from 'react';
import { createRoot } from 'react-dom/client';
import $ from 'jquery';
import { NotFound } from '../component/Body';
import Home from '../component/pages/Home';
import About from '../component/pages/About';
import Portfolio from '../component/pages/Portfolio';
import { API } from './API';

document.addEventListener('DOMContentLoaded', function(e) {
  getPages(window.location.pathname,2);
});

window.onpopstate = function historyback() {
  getPages(window.location.pathname,2);
};

$(document).on('click','a', function(e) {
  let links = $(this).attr('href'),
      target = $(this).attr('target');

  if(links !== '#') {
    (links.substring(0,1) === '/') ? getPages(links,1) : window.open(links,target)
  }
  
  return false;
});

export const getPages = (request,type) => {
  let pages;
  (request === '/') ? pages = 'home' : pages = encodeURIComponent(request.substring(1))
  
  const query = encodeURIComponent(`select * where B = '${pages}'`);

  document.body.scrollTop = 0;
  document.documentElement.scrollTop = 0;

  const getData = async () => {
    await fetch(
      `https://docs.google.com/a/google.com/spreadsheets/d/${API.SPREADSHEET}/gviz/tq?tqx=out:json&sheet=${API.SPREADSHEET_PAGES}&tq=${query}&key=${API.KEY}`
    )
    .then(response => response.text())
    .then(result => {
      const data = JSON.parse(result.substring(47).slice(0, -2));
      if(data.table.rows.length > 0) {
        document.title = data.table.rows[0].c[2].v;
        document.getElementsByTagName('meta')[3].content = data.table.rows[0].c[3].v;
        document.getElementsByTagName('meta')[4].content = 'Aditya Adam Firdaus';
      }else{
        document.title = 'Page Not Found / Aditya Adam F.';
        document.getElementsByTagName('meta')[3].content = 'Page Not Found';
        document.getElementsByTagName('meta')[4].content = 'Aditya Adam Firdaus';
      }

      const bodycontainer = document.getElementsByClassName('AdityaContent')[0];
      const contentroot = createRoot(bodycontainer);
      contentroot.render(
        <>
          {(data.table.rows.length > 0 && listContent(data.table.rows[0].c[1].v) !== undefined) ?
            listContent(data.table.rows[0].c[1].v)
          :
            <NotFound key={Math.random()} />
          }
        </>
      );
    });
  };

  getData();

  if(request !== window.location.pathname) {
    if(pages === 'home' && type === 1) {
      window.history.pushState({'html':'/','pageTitle':document.title},'', '/')
    }else if(pages !== 'home' && type === 1) {
      window.history.pushState({prevUrl: window.location.href,'html':request,'pageTitle':document.title},'', request)
    }
  }
};

const listContent = (key) => {
  const list = {
    home: <Home key={key} />, 
    about: <About key={key} />, 
    portfolio: <Portfolio key={key} />
  }

  return list[key];
}